  ('lifesciences.pharmacovigilance', 'deliverables.title', $q$What You Receive$q$),
  ('lifesciences.pharmacovigilance', 'intro.p3', $q$Every report passes through medically trained linguists and a qualified reviewer, with MedDRA-coded terminology applied consistently so your translated narratives are ready for direct entry into safety databases and regulatory submission.$q$),
  ('lifesciences.regulatory-affairs', 'deliverables.item1_desc', $q$Fully formatted, agency-aligned translations of your CTD modules, labeling, and supporting documents, ready to drop into your dossier.$q$),
  ('lifesciences.regulatory-affairs', 'deliverables.item1_title', $q$Submission-Ready Translations$q$),
